#include <iostream>
#include <stdexcept>
int requirePositive(int value) {
  if (value <= 0) throw std::invalid_argument("value must be positive");
  return value;
}
int main() {
  try {
    std::cout << requirePositive(-2) << "\n";
  } catch (const std::invalid_argument& error) {
    std::cout << error.what() << "\n";
  }
}

